const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const services = JSON.parse(localStorage.getItem('services') || '[]');
const metadataRaw = localStorage.getItem('_metadata');
const metadata = metadataRaw ? JSON.parse(metadataRaw) : null;

// Baseline date ("today")
const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseDate = new Date(baselineDateStr + 'T00:00:00');

function formatDate(d) { return d.toISOString().slice(0, 10); }
function getUpcomingSaturday(d) {
  const day = d.getDay(); // 0=Sun..6=Sat
  let offset = (6 - day + 7) % 7;
  if (offset === 0) offset = 7; // "upcoming" Saturday after today
  const result = new Date(d.getTime());
  result.setDate(result.getDate() + offset);
  return result;
}

const targetDateStr = formatDate(getUpcomingSaturday(baseDate));

// Cooling services that allow standard booking
const coolingServiceIds = services
  .filter(s => s && s.category === 'cooling' && s.hasStandardBooking)
  .map(s => s.id);

// All standard cooling bookings in ZIP 30301
const standardCoolingBookings = bookings.filter(b => {
  if (!b) return false;
  if (!coolingServiceIds.includes(b.serviceId)) return false;
  if (b.bookingType !== 'service') return false;
  if (b.serviceLevel !== 'standard') return false;
  if (b.zip !== '30301') return false;
  return true;
});

// Bookings that are on the nearest upcoming Saturday in the 9–11 AM window
const saturdayMorningBookings = standardCoolingBookings.filter(b => {
  const start = new Date(b.appointmentStart);
  const end = new Date(b.appointmentEnd);
  const dateStr = formatDate(start);
  const startHour = start.getHours();
  const endHour = end.getHours();
  return (
    dateStr === targetDateStr &&
    startHour === 9 &&
    endHour === 11
  );
});

// CP1 (0.4): User submitted a standard cooling booking in ZIP 30301 (action + basic correctness)
checkpoints.push({ passed: standardCoolingBookings.length > 0, weight: 0.4 });

// CP2 (0.6): That booking is on the nearest upcoming Saturday in the 9–11 AM window
checkpoints.push({ passed: saturdayMorningBookings.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const quoteRequests = JSON.parse(localStorage.getItem('installation_quote_requests') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');

// Qualifying high-efficiency furnaces
const qualifyingFurnaces = products.filter(p => {
  if (!p) return false;
  if (p.categoryKey !== 'heating_systems') return false;
  if (p.efficiencyType !== 'afue') return false;
  if (typeof p.efficiencyValue !== 'number' || p.efficiencyValue < 95) return false;
  if (!p.isHighEfficiency) return false;
  if (typeof p.price !== 'number' || p.price > 3500) return false;
  return true;
});

// Determine the highest-rated qualifying furnace (rating desc, then ratingCount desc)
let topFurnace = null;
if (qualifyingFurnaces.length > 0) {
  const sorted = [...qualifyingFurnaces].sort((a, b) => {
    const ra = typeof a.ratingAverage === 'number' ? a.ratingAverage : 0;
    const rb = typeof b.ratingAverage === 'number' ? b.ratingAverage : 0;
    if (rb !== ra) return rb - ra;
    const ca = typeof a.ratingCount === 'number' ? a.ratingCount : 0;
    const cb = typeof b.ratingCount === 'number' ? b.ratingCount : 0;
    return cb - ca;
  });
  topFurnace = sorted[0];
}

// Quote requests for qualifying furnaces
const qualifyingRequests = quoteRequests.filter(q => {
  if (!q) return false;
  const prod = products.find(p => p.id === q.productId);
  return !!prod && qualifyingFurnaces.some(p => p.id === prod.id);
});

// Quote requests specifically for the top (highest-rated) qualifying furnace
const topFurnaceRequests = topFurnace
  ? qualifyingRequests.filter(q => q.productId === topFurnace.id)
  : [];

// CP1 (0.4): User submitted a quote request for some qualifying high-efficiency furnace (action + criteria)
checkpoints.push({ passed: qualifyingRequests.length > 0, weight: 0.4 });

// CP2 (0.6): The quote request is for the highest-rated qualifying furnace
checkpoints.push({ passed: topFurnaceRequests.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const orders = JSON.parse(localStorage.getItem('orders') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const plans = JSON.parse(localStorage.getItem('maintenance_plans') || '[]');

// Qualifying plans: annual, include heating & cooling, pricePerYear <= 200, active
const qualifyingPlans = plans.filter(p => {
  if (!p) return false;
  if (p.billingTerm !== 'annual') return false;
  if (!p.includesHeating || !p.includesCooling) return false;
  if (typeof p.pricePerYear !== 'number' || p.pricePerYear > 200) return false;
  if (!p.isActive) return false;
  return true;
});

// Determine the cheapest qualifying plan(s)
let cheapestPrice = null;
let cheapestPlanIds = [];
qualifyingPlans.forEach(p => {
  const price = typeof p.pricePerYear === 'number' ? p.pricePerYear : Infinity;
  if (cheapestPrice === null || price < cheapestPrice) {
    cheapestPrice = price;
    cheapestPlanIds = [p.id];
  } else if (price === cheapestPrice) {
    cheapestPlanIds.push(p.id);
  }
});

function cartItemsForCart(cartId) {
  return cartItems.filter(ci => ci.cartId === cartId);
}

// Find orders that include at least one qualifying plan
const ordersWithQualifyingPlan = orders.filter(order => {
  if (!order) return false;
  const items = cartItemsForCart(order.cartId);
  return items.some(ci => {
    if (!ci || ci.itemType !== 'maintenance_plan' || !ci.maintenancePlanId) return false;
    return qualifyingPlans.some(p => p.id === ci.maintenancePlanId);
  });
});

// Among those, find orders that include the cheapest qualifying plan
const ordersWithCheapestPlan = ordersWithQualifyingPlan.filter(order => {
  const items = cartItemsForCart(order.cartId);
  return items.some(ci => {
    if (!ci || ci.itemType !== 'maintenance_plan' || !ci.maintenancePlanId) return false;
    return cheapestPlanIds.includes(ci.maintenancePlanId);
  });
});

// CP1 (0.4): User placed an order that includes some qualifying annual heating & cooling plan under $200
checkpoints.push({ passed: ordersWithQualifyingPlan.length > 0, weight: 0.4 });

// CP2 (0.6): The order includes the cheapest qualifying plan
checkpoints.push({ passed: ordersWithCheapestPlan.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const services = JSON.parse(localStorage.getItem('services') || '[]');
const offers = JSON.parse(localStorage.getItem('special_offers') || '[]');
const metadataRaw = localStorage.getItem('_metadata');
const metadata = metadataRaw ? JSON.parse(metadataRaw) : null;

// Baseline date
const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseDate = new Date(baselineDateStr + 'T00:00:00');

function formatDate(d) { return d.toISOString().slice(0, 10); }

// 15th of next month
const nextMonthDate = new Date(baseDate.getTime());
nextMonthDate.setMonth(nextMonthDate.getMonth() + 1);
nextMonthDate.setDate(15);
const targetDateStr = formatDate(nextMonthDate);

const now = baseDate; // align with scenario timing

// Active duct_services promotions meeting discount criteria
const ductOffers = offers.filter(o => {
  if (!o) return false;
  if (o.category !== 'duct_services') return false;
  if (!o.isActive) return false;
  if (o.startDate && new Date(o.startDate) > now) return false;
  if (o.endDate && new Date(o.endDate) < now) return false;
  const percentOk = (o.discountType === 'percentage' && typeof o.discountPercent === 'number' && o.discountPercent >= 15);
  const priceOk = (typeof o.promotionalPrice === 'number' && o.promotionalPrice <= 250);
  return percentOk || priceOk;
});

// First qualifying offer by data order
const firstOffer = ductOffers.length > 0 ? ductOffers[0] : null;
const firstOfferId = firstOffer ? firstOffer.id : null;

// Duct service IDs
const ductServiceIds = services.filter(s => s && s.category === 'duct_services').map(s => s.id);

// Bookings that use the first qualifying offer on a duct service
const bookingsWithFirstOffer = bookings.filter(b => {
  if (!b) return false;
  if (!firstOfferId) return false;
  if (b.offerId !== firstOfferId) return false;
  if (!ductServiceIds.includes(b.serviceId)) return false;
  if (b.bookingType !== 'service') return false;
  return true;
});

// Among those, find ones on the 15th of next month in an afternoon time slot (start between 12:00–17:59)
const afternoonTargetBookings = bookingsWithFirstOffer.filter(b => {
  const start = new Date(b.appointmentStart);
  const dateStr = formatDate(start);
  const hour = start.getHours();
  return dateStr === targetDateStr && hour >= 12 && hour < 18;
});

// CP1 (0.4): User booked a duct cleaning service using the first qualifying duct-services promotion
checkpoints.push({ passed: bookingsWithFirstOffer.length > 0, weight: 0.4 });

// CP2 (0.6): That booking is on the 15th of next month in an afternoon time slot
checkpoints.push({ passed: afternoonTargetBookings.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const services = JSON.parse(localStorage.getItem('services') || '[]');
const metadataRaw = localStorage.getItem('_metadata');
const metadata = metadataRaw ? JSON.parse(metadataRaw) : null;

// Baseline date as today
const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const today = new Date(baselineDateStr + 'T00:00:00');

function formatDate(d) { return d.toISOString().slice(0, 10); }
const todayStr = formatDate(today);

// Heating services
const heatingServiceIds = services.filter(s => s && s.category === 'heating').map(s => s.id);

function isEmergencyBooking(b) {
  return b.bookingType === 'emergency' || b.serviceLevel === 'emergency' || b.serviceLevel === 'after_hours';
}

// Emergency heating bookings for ZIP 30309 today
const emergencyToday = bookings.filter(b => {
  if (!b) return false;
  if (!heatingServiceIds.includes(b.serviceId)) return false;
  if (!isEmergencyBooking(b)) return false;
  if (b.zip !== '30309') return false;
  const start = new Date(b.appointmentStart);
  const dateStr = formatDate(start);
  return dateStr === todayStr;
});

// Among those, ones starting at or after 8 PM
const emergencyAfter8 = emergencyToday.filter(b => {
  const start = new Date(b.appointmentStart);
  const hour = start.getHours();
  return hour >= 20; // 20:00 or later
});

// CP1 (0.4): User submitted an emergency heating booking for ZIP 30309 for today
checkpoints.push({ passed: emergencyToday.length > 0, weight: 0.4 });

// CP2 (0.6): That booking starts at or after 8:00 PM
checkpoints.push({ passed: emergencyAfter8.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkouts = [];
const checkpoints = checkouts; // alias to follow pattern wording

const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const services = JSON.parse(localStorage.getItem('services') || '[]');
const metadataRaw = localStorage.getItem('_metadata');
const metadata = metadataRaw ? JSON.parse(metadataRaw) : null;

// Baseline date
const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baseDate = new Date(baselineDateStr + 'T00:00:00');

function formatDate(d) { return d.toISOString().slice(0, 10); }

// Date exactly two weeks from today
const targetDate = new Date(baseDate.getTime());
targetDate.setDate(targetDate.getDate() + 14);
const targetDateStr = formatDate(targetDate);

// Qualifying Wi-Fi smart thermostats
const qualifyingThermostats = products.filter(p => {
  if (!p) return false;
  if (p.categoryKey !== 'thermostats') return false;
  if (typeof p.price !== 'number' || p.price > 250) return false;
  if (typeof p.ratingAverage !== 'number' || p.ratingAverage < 4.0) return false;
  const tags = Array.isArray(p.featureTags) ? p.featureTags : [];
  if (!tags.includes('wifi_enabled')) return false;
  return true;
});

// Most affordable qualifying thermostat
let cheapestThermostat = null;
if (qualifyingThermostats.length > 0) {
  const sorted = [...qualifyingThermostats].sort((a, b) => {
    const pa = typeof a.price === 'number' ? a.price : Infinity;
    const pb = typeof b.price === 'number' ? b.price : Infinity;
    if (pa !== pb) return pa - pb;
    return (a.ratingAverage || 0) - (b.ratingAverage || 0);
  });
  cheapestThermostat = sorted[0];
}

// Installation services
const installationServiceIds = services.filter(s => s && s.category === 'installation').map(s => s.id);

// All installation bookings on the target date associated with thermostat products
const installBookingsOnDate = bookings.filter(b => {
  if (!b) return false;
  if (b.bookingType !== 'installation') return false;
  if (!installationServiceIds.includes(b.serviceId)) return false;
  if (!b.productId) return false;
  const prod = products.find(p => p.id === b.productId);
  if (!prod || prod.categoryKey !== 'thermostats') return false;
  const start = new Date(b.appointmentStart);
  const dateStr = formatDate(start);
  return dateStr === targetDateStr;
});

// Bookings that are for qualifying thermostats on that date
const qualifyingInstallBookings = installBookingsOnDate.filter(b => {
  const prod = products.find(p => p.id === b.productId);
  return !!prod && qualifyingThermostats.some(p => p.id === prod.id);
});

// Among those, bookings that are for the cheapest qualifying thermostat in the 10–12 window
const bestWindowBookings = qualifyingInstallBookings.filter(b => {
  if (!cheapestThermostat) return false;
  if (b.productId !== cheapestThermostat.id) return false;
  const start = new Date(b.appointmentStart);
  const end = new Date(b.appointmentEnd);
  const sh = start.getHours();
  const eh = end.getHours();
  return sh === 10 && eh === 12;
});

// CP1 (0.4): User scheduled installation on the correct date for some qualifying Wi-Fi thermostat
checkpoints.push({ passed: qualifyingInstallBookings.length > 0, weight: 0.4 });

// CP2 (0.6): That booking is for the cheapest qualifying thermostat and in the 10–12 AM window
checkpoints.push({ passed: bestWindowBookings.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const applications = JSON.parse(localStorage.getItem('financing_applications') || '[]');
const plans = JSON.parse(localStorage.getItem('financing_plans') || '[]');

// Applications that use an active 0% APR plan with term >= 12 months for a $5,000 new air conditioner
const coreQualifyingApps = applications.filter(app => {
  if (!app) return false;
  const plan = plans.find(p => p.id === app.financingPlanId);
  if (!plan || !plan.isActive) return false;
  if (!plan.isZeroApr) return false;
  if (typeof plan.termMonths !== 'number' || plan.termMonths < 12) return false;
  if (app.purchasePurpose !== 'new_air_conditioner') return false;
  if (typeof app.purchaseAmount !== 'number' || app.purchaseAmount !== 5000) return false;
  return true;
});

// Among those, require email as preferred contact method
const emailQualifyingApps = coreQualifyingApps.filter(app => app.preferredContactMethod === 'email');

// CP1 (0.5): User submitted a financing application matching amount, purpose, and a qualifying 0% ≥12-month plan
checkpoints.push({ passed: coreQualifyingApps.length > 0, weight: 0.5 });

// CP2 (0.5): That application also selected email as the preferred contact method
checkpoints.push({ passed: emailQualifyingApps.length > 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const services = JSON.parse(localStorage.getItem('services') || '[]');
const articles = JSON.parse(localStorage.getItem('blog_articles') || '[]');
const metadataRaw = localStorage.getItem('_metadata');
const metadata = metadataRaw ? JSON.parse(metadataRaw) : null;

// Baseline date as "today"
const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const today = new Date(baselineDateStr + 'T00:00:00');

function formatDate(d) { return d.toISOString().slice(0, 10); }

// Find indoor air quality articles (title/excerpt/content contains 'indoor air quality')
const iaqArticles = articles.filter(a => {
  if (!a) return false;
  const text = ((a.title || '') + ' ' + (a.excerpt || '') + ' ' + (a.content || '')).toLowerCase();
  return text.includes('indoor air quality');
});

// Recommended service IDs from those articles
const iaqRecommendedServiceIdsSet = new Set();
iaqArticles.forEach(a => {
  const ids = Array.isArray(a.recommendedServiceIds) ? a.recommendedServiceIds : [];
  ids.forEach(id => iaqRecommendedServiceIdsSet.add(id));
});

// IAQ services that support consultation and are recommended
const iaqConsultServiceIds = services
  .filter(s => {
    if (!s) return false;
    if (s.category !== 'indoor_air_quality') return false;
    if (!s.hasConsultationOption) return false;
    return iaqRecommendedServiceIdsSet.has(s.id);
  })
  .map(s => s.id);

// All consultation bookings for one of these services
const iaqConsultBookings = bookings.filter(b => {
  if (!b) return false;
  if (b.bookingType !== 'consultation') return false;
  if (!iaqConsultServiceIds.includes(b.serviceId)) return false;
  return true;
});

// Among those, bookings within the next 7 days (excluding today), weekdays only, afternoon time slot
const millisPerDay = 24 * 60 * 60 * 1000;

const qualifyingAfternoonBookings = iaqConsultBookings.filter(b => {
  const start = new Date(b.appointmentStart);
  const dateStr = formatDate(start);
  const diffDays = Math.round((start.getTime() - today.getTime()) / millisPerDay);
  if (diffDays < 1 || diffDays > 7) return false; // within next 7 days, not today
  const dow = start.getDay(); // 0=Sun..6=Sat
  if (dow === 0 || dow === 6) return false; // weekdays only
  const hour = start.getHours();
  if (hour < 12 || hour >= 18) return false; // afternoon window
  return true;
});

// CP1 (0.4): User submitted a consultation booking for an IAQ service recommended in an indoor air quality article
checkpoints.push({ passed: iaqConsultBookings.length > 0, weight: 0.4 });

// CP2 (0.6): That booking is on a weekday within the next 7 days in an afternoon time slot
checkpoints.push({ passed: qualifyingAfternoonBookings.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
